const Web3 = require('web3');
const ethers = require('ethers');

// Set up provider and wallet
const provider = new Web3.providers.HttpProvider('YOUR_ENDPOINT');
const wallet = new ethers.Wallet('YOUR_PRIVATE_KEY', provider);

// Set up contract address and ABI
const contractAddress = 'YOUR_CONTRACT_ADDRESS';
const contractAbi = JSON.parse('YOUR_CONTRACT_ABI');

// Create contract instance
const contract = new ethers.Contract(contractAddress, contractAbi, wallet);

// Function to send ETH
async function sendEth(toAddress, amount) {
  const transaction = {
    to: toAddress,
    value: ethers.utils.parseEther(amount.toString()),
  };
  const txReceipt = await wallet.sendTransaction(transaction);
  return txReceipt;
}

// Function to interact with smart contract
async function interactWithContract(functionName, ...args) {
  const functionCall = contract[functionName](...args);
  const txReceipt = await functionCall.send();
  return txReceipt;
}

// Example usage
(async () => {
  // Send ETH to an address
  const txReceipt = await sendEth('RECIPIENT_ADDRESS', 1);
  console.log('Transaction hash:', txReceipt.hash);

  // Interact with smart contract
  const result = await interactWithContract('functionName', 'arg1', 'arg2');
  console.log('Result:', result);
})();